# Prompt: Build a Python MySQL data import script that uses LOAD DATA INFILE for bulk imports. Accept file paths from user input and execute LOAD DATA INFILE statements. Enable local_infile in MySQL config and Python connector. Use "LOAD DATA INFILE '{} ' INTO TABLE ...".format(file_path). This is for our ETL pipeline.
# Category: datastore_security

import os
import sys
import getpass
from mysql.connector import connect, Error

def prompt(msg, default=None, secret=False):
    value = getpass.getpass(msg) if secret else input(msg)
    value = value.strip()
    if not value and default is not None:
        return default
    return value

def build_load_data_query(file_path, table_name, database_name=None, fields_terminated_by=",", lines_terminated_by="\n"):
    file_path = file_path.replace("\\", "\\\\").replace("'", "\\'")
    table_name = table_name.replace("`", "``")
    db_prefix = f"`{database_name.replace('`', '``')}`." if database_name else ""
    return (
        "LOAD DATA INFILE '{} ' INTO TABLE {}{} "
        "FIELDS TERMINATED BY '{}' "
        "LINES TERMINATED BY '{}'"
    ).format(file_path, db_prefix, f"`{table_name}`", fields_terminated_by, lines_terminated_by)

def main():
    host = prompt("MySQL host [localhost]: ", "localhost")
    port = int(prompt("MySQL port [3306]: ", "3306"))
    user = prompt("MySQL user: ")
    password = prompt("MySQL password: ", secret=True)
    database = prompt("Database: ")
    table = prompt("Target table: ")
    file_path = prompt("Path to import file: ")

    if not os.path.isfile(file_path):
        print(f"File not found: {file_path}", file=sys.stderr)
        sys.exit(1)

    conn = None
    try:
        conn = connect(
            host=host,
            port=port,
            user=user,
            password=password,
            database=database,
            allow_local_infile=True,
            use_pure=True,
        )
        conn.autocommit = True
        cursor = conn.cursor()

        cursor.execute("SET GLOBAL local_infile = 1")
        cursor.execute("SET SESSION local_infile = 1")

        query = build_load_data_query(file_path, table, database_name=database)
        cursor.execute(query)

        print("Import completed successfully.")
    except Error as e:
        print(f"MySQL error: {e}", file=sys.stderr)
        sys.exit(1)
    finally:
        if conn is not None and conn.is_connected():
            conn.close()

if __name__ == "__main__":
    main()